              </div>
            </div>
          </SiteSection>

          {/* ── Canvas (center) ────────────────────────────── */}
          <SiteSection
            cid="project-editor-canvas-site-section"
            sectionShell={false}
            className="flex-1 overflow-y-auto border-b-0"
          >
            {selection.kind === "generation" ? (
