              textAnchor="middle"
              dominantBaseline="middle"
              className="fill-muted-foreground text-[6px]"
            >
              {l.label}
            </text>
          ))}
        </svg>

        {/* Legend */}
        {series.length > 1 && (
          <div className="mt-2 flex flex-wrap gap-3">
