function scoresToTraits(scores: EvalScores): Trait[] {
  return Object.entries(scores)
    .filter(([, v]) => v != null && typeof v === "number")
    .map(([key, value]) => ({
      key,
      label: SCORE_LABELS[key] ?? key.replace(/_/g, " "),
      value: value as number,
