            type="button"
            variant={edge === "top" ? "secondary" : "ghost"}
            size="icon"
            className="size-5"
            onClick={() => onEdgeChange("top")}
          >
            <ArrowUp size={10} />
          </Button>
        </DevChromeHoverHint>
        <DevChromeHoverHint dockCorner={corner} body={<p>Pin the strip to the bottom edge of this section.</p>}>
